const API_URL = 'http://localhost:5000/api';

async function getAll() {
    const response = await fetch(`${API_URL}/attacks`);
    if (!response.ok) throw new Error('Failed to fetch');
    const data = await response.json();
    return { data };
}

async function getOne(id) {
    const response = await fetch(`${API_URL}/attacks/${id}`);
    if (!response.ok) throw new Error('Failed to fetch');
    const data = await response.json();
    return { data };
}

async function create(data) {
    const response = await fetch(`${API_URL}/attacks`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data)
    });
    if (!response.ok) throw new Error('Failed to create');
    const result = await response.json();
    return { data: result };
}

async function update(id, data) {
    console.log('Updating item:', id, data);
    const response = await fetch(`${API_URL}/attacks/${id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data)
    });
    console.log('Update response status:', response.status);
    if (!response.ok) {
        const error = await response.json();
        console.log('Update error:', error);
        throw new Error(error.error || 'Failed to update');
    }
    const result = await response.json();
    return { data: result };
}

async function remove(id) {
    const response = await fetch(`${API_URL}/attacks/${id}`, {
        method: 'DELETE'
    });
    const text = await response.text();
    console.log('Delete response status:', response.status);
    console.log('Delete response body:', text);

    if (!response.ok) {
        let errorMsg = 'Failed to delete';
        try {
            const errorJson = JSON.parse(text);
            errorMsg = errorJson.error || errorMsg;
        } catch(e) {
            errorMsg = text || errorMsg;
        }
        throw new Error(errorMsg);
    }
    return { data: { id } };
}

async function getStatistics() {
    const response = await fetch(`${API_URL}/statistics`);
    if (!response.ok) throw new Error('Failed to fetch stats');
    const data = await response.json();
    return { data };
}

async function testFunctions() {
    const response = await fetch(`${API_URL}/test-functions`);
    if (!response.ok) throw new Error('Failed to test');
    const data = await response.json();
    return { data };
}

export { getAll, getOne, create, update, remove, getStatistics, testFunctions };
